                return allocator.dupe(u8, "");
            }
        }.call,
        .chat = struct {
            fn call(_: *anyopaque, allocator: std.mem.Allocator, _: providers.ChatRequest, _: []const u8, _: f64) anyerror!providers.ChatResponse {
                return .{
                    .content = try allocator.dupe(u8, "unused"),
