    const signing_secret = "strict_slack_secret";
    const body =
        \\{"type":"event_callback","event":{"type":"message","user":"U_STRICT","text":"hello","channel":"D_STRICT","channel_type":"im","event_ts":"1700000000","ts":"1700000000"}}
    ;
