// ── P0-1: acceptor-thread probe fast-path classifier tests ───────────
//
// The acceptor fast-path itself requires a live socket (verified under
// load at staging retest — full saturation + /health latency). Here we pin
// the smallest extractable, race-free unit: classifyProbeRequestLine, which
// decides whether a peeked request line is a GET /health or GET /ready
// probe the acceptor may answer inline without enqueueing.

test "P0-1 classifier: GET /health is a health probe" {
    try std.testing.expectEqual(ProbeClass.health, classifyProbeRequestLine("GET /health HTTP/1.1\r\nHost: x\r\n\r\n"));
}

test "P0-1 classifier: GET /ready is a ready probe" {
    try std.testing.expectEqual(ProbeClass.ready, classifyProbeRequestLine("GET /ready HTTP/1.1\r\nHost: x\r\n\r\n"));
}

test "P0-1 classifier: health/ready accept a query string" {
    try std.testing.expectEqual(ProbeClass.health, classifyProbeRequestLine("GET /health?probe=1 HTTP/1.1\r\n\r\n"));
    try std.testing.expectEqual(ProbeClass.ready, classifyProbeRequestLine("GET /ready?x=1 HTTP/1.1\r\n\r\n"));
}

test "P0-1 classifier: only GET is fast-pathed" {
    // Non-GET requests to these paths must fall through to the worker so the
    // existing dispatch (and any future method handling) is unchanged.
    try std.testing.expectEqual(ProbeClass.other, classifyProbeRequestLine("POST /health HTTP/1.1\r\n\r\n"));
    try std.testing.expectEqual(ProbeClass.other, classifyProbeRequestLine("HEAD /ready HTTP/1.1\r\n\r\n"));
}

test "P0-1 classifier: non-probe paths are not fast-pathed" {
    try std.testing.expectEqual(ProbeClass.other, classifyProbeRequestLine("GET / HTTP/1.1\r\n\r\n"));
    try std.testing.expectEqual(ProbeClass.other, classifyProbeRequestLine("GET /metrics HTTP/1.1\r\n\r\n"));
    try std.testing.expectEqual(ProbeClass.other, classifyProbeRequestLine("GET /api/v1/chat HTTP/1.1\r\n\r\n"));
}

test "P0-1 classifier: prefix paths are NOT misclassified" {
    // A longer path must never be mistaken for the exact probe path.
    try std.testing.expectEqual(ProbeClass.other, classifyProbeRequestLine("GET /healthz HTTP/1.1\r\n\r\n"));
    try std.testing.expectEqual(ProbeClass.other, classifyProbeRequestLine("GET /health/extra HTTP/1.1\r\n\r\n"));
    try std.testing.expectEqual(ProbeClass.other, classifyProbeRequestLine("GET /readyz HTTP/1.1\r\n\r\n"));
}

test "P0-1 classifier: a partial request line (no CRLF) is not classified" {
    // A peek that has not yet received the full request line must return
    // .other so the connection falls through to the normal worker path —
    // never a guess on a truncated path like "GET /healt".
    try std.testing.expectEqual(ProbeClass.other, classifyProbeRequestLine("GET /healt"));
    try std.testing.expectEqual(ProbeClass.other, classifyProbeRequestLine("GET /health HTTP/1.1"));
    try std.testing.expectEqual(ProbeClass.other, classifyProbeRequestLine(""));
    try std.testing.expectEqual(ProbeClass.other, classifyProbeRequestLine("GE"));
}

// ── C3: liveness deadlock watchdog predicate tests ───────────────────
//
// The watchdog predicate is a PURE function of (queue_depth,
// ms_since_last_progress, threshold_ms) so the three acceptance cases —
// WEDGED, IDLE, BUSY — are pinned here without spinning real worker threads.
// "progress" = a worker popped (started) OR completed any request (Finding
// C3-2). The whole point is no restart-loop risk: idle and busy must NEVER flag.

test "C3 predicate: WEDGED pool (pending work + no pop/complete past threshold) is flagged" {
    // 5 requests queued, no worker popped or completed for 200s, 180s
    // threshold → deadlock.
    try std.testing.expect(isWorkerPoolDeadlocked(5, 0, 200_000, 180_000));
    // Exactly one request stuck is enough — depth > 0 is the gate, not a count.
    try std.testing.expect(isWorkerPoolDeadlocked(1, 0, 181_000, 180_000));
}

test "C3 predicate (Wave-E): IN-FLIGHT-only wedge (queue drained, no new traffic) is flagged" {
    // All workers POPPED their requests then wedged mid-handling: the queue
    // drained to 0 but in_flight_requests stays > 0, and no new traffic arrives
    // to re-grow the queue. The OLD queue-only gate (queue_depth == 0 → idle)
    // would NEVER flag this — the exact false-negative this fix closes. With
    // in_flight > 0 counted as work present, a no-progress gap past the
    // threshold now trips.
    try std.testing.expect(isWorkerPoolDeadlocked(0, 4, 200_000, 180_000));
    try std.testing.expect(isWorkerPoolDeadlocked(0, 1, 181_000, 180_000));
    // Queue empty AND nothing in flight → still idle, never flagged (below).
}

test "C3 predicate: IDLE runtime (no pending work) is NEVER flagged" {
    // No queued work AND nothing in flight → not a deadlock, no matter how long
    // since last progress. "No progress" on an idle pool is normal, not a wedge
    // — this is the primary restart-loop guard.
    try std.testing.expect(!isWorkerPoolDeadlocked(0, 0, 10_000_000, 180_000));
    try std.testing.expect(!isWorkerPoolDeadlocked(0, 0, 200_000, 180_000));
    try std.testing.expect(!isWorkerPoolDeadlocked(0, 0, 0, 180_000));
}

test "C3 predicate: BUSY-but-progressing runtime is NOT flagged" {
    // Pending work exists, but the pool serviced the queue recently — a worker
    // popped or completed a request (gap < threshold) → the pool is making
    // progress, never flagged even with a continuously non-empty queue under
    // sustained load and long individual turns (Finding C3-2: a pop counts as
    // progress, so all-workers-busy-on-long-turns that still drains the queue
    // is not mistaken for a wedge).
    try std.testing.expect(!isWorkerPoolDeadlocked(50, 0, 1_000, 180_000));
    try std.testing.expect(!isWorkerPoolDeadlocked(1, 0, 179_999, 180_000));
    // Boundary: a gap exactly AT the threshold is not yet a deadlock (strict >).
    try std.testing.expect(!isWorkerPoolDeadlocked(3, 0, 180_000, 180_000));
    // Wave-E: an IN-FLIGHT request that is PROGRESSING (recent heartbeat keeps
    // the gap small) is likewise not flagged, even with the queue drained — the
    // restart-loop-safety guarantee for the new in_flight gate.
    try std.testing.expect(!isWorkerPoolDeadlocked(0, 4, 1_000, 180_000));
    try std.testing.expect(!isWorkerPoolDeadlocked(0, 1, 179_999, 180_000));
}

test "C3 predicate: threshold 0 disables the watchdog" {
    // Even a clearly wedged pool is not flagged when the knob is 0 — the
    // operator kill-switch reverts cheap /health to pure acceptor liveness.
    try std.testing.expect(!isWorkerPoolDeadlocked(100, 0, 999_999_999, 0));
    try std.testing.expect(!isWorkerPoolDeadlocked(0, 100, 999_999_999, 0));
}

test "C3 livenessDeadlockDetected: wedged state via injected timestamps" {
    var state = GatewayState.init(std.testing.allocator);
    defer state.deinit();
    state.liveness_deadlock_threshold_ms = 180_000;

    // Boot: progress seeded to t=0, no queued work and nothing in flight →
    // not flagged regardless of how far `now` has advanced (idle-from-boot is
    // not a deadlock).
    state.last_worker_progress_ms.store(0, .release);
    state.queued_requests.store(0, .release);
    state.in_flight_requests.store(0, .release);
    try std.testing.expect(!livenessDeadlockDetected(&state, 10_000_000));

    // Work arrives and a worker last completed at t=1000ms; now=300_000ms →
    // 299s with no completion and pending work → WEDGED.
    state.queued_requests.store(4, .release);
    state.last_worker_progress_ms.store(1_000, .release);
    try std.testing.expect(livenessDeadlockDetected(&state, 300_000));

    // A worker just completed (progress catches up to ~now) → BUSY, cleared.
    state.last_worker_progress_ms.store(299_500, .release);
    try std.testing.expect(!livenessDeadlockDetected(&state, 300_000));

    // Queue drains to empty while progress stays old → IDLE, not flagged.
    state.queued_requests.store(0, .release);
    state.last_worker_progress_ms.store(1_000, .release);
    try std.testing.expect(!livenessDeadlockDetected(&state, 300_000));

    // Wave-E: queue is empty but a request is IN FLIGHT (worker popped then
    // wedged) with ancient progress → WEDGED, now caught via the in_flight gate.
    state.queued_requests.store(0, .release);
    state.in_flight_requests.store(2, .release);
    state.last_worker_progress_ms.store(1_000, .release);
    try std.testing.expect(livenessDeadlockDetected(&state, 300_000));

    // Same in-flight request but PROGRESSING (recent heartbeat) → cleared.
    state.last_worker_progress_ms.store(299_500, .release);
    try std.testing.expect(!livenessDeadlockDetected(&state, 300_000));
    state.in_flight_requests.store(0, .release);

    // Threshold 0 disables even with a wedged-looking state.
    state.liveness_deadlock_threshold_ms = 0;
    state.queued_requests.store(4, .release);
    state.last_worker_progress_ms.store(1_000, .release);
    try std.testing.expect(!livenessDeadlockDetected(&state, 300_000));
}

test "C3 Finding C3-2: a recent POP clears the watchdog even with no recent completion" {
    // The regression this guards: all workers busy on long, PROGRESSING turns
    // while requests queue. A single agentic turn has no wall-clock bound
    // (max_tool_iterations defaults to maxInt(u32); only each provider.chat is
    // bounded by message_timeout_secs), so a "time since last COMPLETION"
    // watchdog would 503 a healthy pool into a restart loop. The fix advances
    // last_worker_progress_ms when a worker POPS the next queued item too
    // (gatewayWorkerMain stores it before handling), so a pool that is still
    // draining the queue keeps the clock fresh between completions.
    var state = GatewayState.init(std.testing.allocator);
    defer state.deinit();
    state.liveness_deadlock_threshold_ms = 180_000;

    // Pending work, and the last COMPLETION was ancient (a worker has been
    // inside one long turn for ~600s) — under the old "since completion" model
    // this would FALSE-POSITIVE as wedged.
    state.queued_requests.store(8, .release);
    state.last_worker_progress_ms.store(0, .release); // ancient
    try std.testing.expect(livenessDeadlockDetected(&state, 600_000));

    // Now a worker returns from its turn and POPS the next queued request:
    // gatewayWorkerMain stores milliTimestamp() on pop. Model that the pop
    // happened ~5s ago. Queue is STILL non-empty (more work behind it), yet
    // the pool is plainly progressing — must NOT be flagged.
    state.last_worker_progress_ms.store(595_000, .release); // popped 5s before "now"
    try std.testing.expect(!livenessDeadlockDetected(&state, 600_000));

    // If even pops stop (no worker pops or completes anything) the gap grows
    // again and a genuine wedge still trips once past the threshold.
    try std.testing.expect(livenessDeadlockDetected(&state, 595_000 + 180_001));
}

test "C3 heartbeat: busy-but-PROGRESSING pool (periodic mid-turn heartbeats) is NOT flagged" {
    // The exact restart-loop bug this fix closes: every worker is busy inside
    // one long multi-iteration turn while requests queue (queued_requests > 0),
    // so NO worker pops or completes anything for far longer than the OLD 900s
    // threshold — but each turn IS progressing and emits a mid-turn heartbeat
    // per iteration / per stream chunk. The heartbeat refreshes the SAME atomic
    // the watchdog reads (last_worker_progress_ms), so a progressing pool is
    // never mistaken for a wedge.
    var state = GatewayState.init(std.testing.allocator);
    defer state.deinit();
    state.liveness_deadlock_threshold_ms = 600_000; // the shipped default

    // Wire the global progress sink at the SAME atomic gatewayWorkerMain seeds
    // and the watchdog reads — this is exactly what runWithRole installs at
    // boot. Detach at end so no other test sees a dangling sink.
    observability.setProgressHeartbeat(&state.last_worker_progress_ms);
    defer observability.setProgressHeartbeat(null);

    // Pending work sits the entire time; no worker ever pops/completes.
    state.queued_requests.store(12, .release);
    // Last pop/completion is ANCIENT — under a pop-or-complete-only model with
    // all workers stuck inside one long turn, the gap would blow past BOTH the
    // old 900s and the new 600s threshold and false-trip.
    state.last_worker_progress_ms.store(0, .release);

    // Model a turn that runs well past the OLD 900s ceiling: simulate periodic
    // mid-turn heartbeats. Each recordProgressHeartbeat() stamps the real
    // monotonic-ish clock into the sink; we then evaluate the predicate against
    // that fresh stamp. As long as a heartbeat lands within the threshold
    // window, the pool is never flagged — no matter how long the overall turn
    // runs (here ~1200s of simulated turn time, well past 900s AND 600s).
    var simulated_turn_elapsed_ms: i64 = 0;
    const heartbeat_interval_ms: i64 = 5_000; // an iteration / stream chunk cadence
    while (simulated_turn_elapsed_ms < 1_200_000) : (simulated_turn_elapsed_ms += heartbeat_interval_ms) {
        // A worker makes progress (tool-loop iteration or stream chunk): the
        // turn calls recordProgressHeartbeat(), stamping `now` into the sink.
        observability.recordProgressHeartbeat();
        const fresh = state.last_worker_progress_ms.load(.acquire);
        // The watchdog evaluates a hair after the heartbeat (well inside the
        // threshold): a freshly-heartbeated, progressing pool is NOT flagged
        // even though queued_requests > 0 and no completion has occurred.
        try std.testing.expect(!livenessDeadlockDetected(&state, fresh + 1_000));
    }

    // Sanity: the sink really advanced the clock far from the ancient seed.
    try std.testing.expect(state.last_worker_progress_ms.load(.acquire) > 0);
}

test "C3 heartbeat: a STUCK pool (queued work, NO heartbeat past threshold) IS flagged" {
    // The counterpart: once the heartbeats STOP (no pop, no completion, no
    // turn iteration / stream chunk from ANY worker) while work is queued, the
    // gap grows past the threshold and the watchdog correctly trips — the pool
    // is genuinely wedged.
    var state = GatewayState.init(std.testing.allocator);
    defer state.deinit();
    state.liveness_deadlock_threshold_ms = 600_000;

    observability.setProgressHeartbeat(&state.last_worker_progress_ms);
    defer observability.setProgressHeartbeat(null);

    // A heartbeat lands, then the pool wedges: no further heartbeat/pop/complete.
    observability.recordProgressHeartbeat();
    const last_beat = state.last_worker_progress_ms.load(.acquire);
    state.queued_requests.store(7, .release);

    // Just before the threshold elapses since the last heartbeat → not yet.
    try std.testing.expect(!livenessDeadlockDetected(&state, last_beat + 600_000));
    // Past the threshold with NO heartbeat in between → genuine wedge, flagged.
    try std.testing.expect(livenessDeadlockDetected(&state, last_beat + 600_001));

    // And idle (queue drains) with the same stale clock is never flagged — the
    // primary restart-loop guard still holds.
    state.queued_requests.store(0, .release);
    try std.testing.expect(!livenessDeadlockDetected(&state, last_beat + 10_000_000));
}

test "C3 heartbeat: no sink installed makes recordProgressHeartbeat a safe no-op" {
    // Tests / standalone CLI never install the sink. recordProgressHeartbeat()
    // must be a harmless no-op (cheap atomic load of a null pointer), touching
    // no state and never crashing.
    observability.setProgressHeartbeat(null);
    observability.recordProgressHeartbeat();
    observability.recordProgressHeartbeat();
}

// A connection with an invalid handle for queue-mechanics tests. NEVER do I/O
// on it and NEVER let RequestQueue.deinit() run with items still queued (deinit
// closes streams) — drain via popWait() so close() is never reached.
fn fakeConnForTest() std.net.Server.Connection {
    return .{
        .stream = .{ .handle = -1 },
        .address = std.net.Address.initIp4(.{ 0, 0, 0, 0 }, 0),
    };
}

test "C3 RequestQueue.push increments the watchdog depth counter under the queue mutex" {
    // The Finding-C3-1 fix moves the queued_requests increment from the
    // acceptor (after push() returned, racing the worker's pop-then-sub) into
    // push() itself, under the queue mutex. Pin the new contract: push bumps
    // the wired counter, and a paired popWait()+fetchSub returns it to zero
    // with no underflow.
    var counter = std.atomic.Value(usize).init(0);
    var q = RequestQueue.init(std.testing.allocator, 8);
    q.depth_counter = &counter;
    defer q.deinit();

    try std.testing.expect(q.push(fakeConnForTest()));
    try std.testing.expectEqual(@as(usize, 1), counter.load(.acquire));
    try std.testing.expect(q.push(fakeConnForTest()));
    try std.testing.expectEqual(@as(usize, 2), counter.load(.acquire));

    // Drain exactly as a worker would: pop, then fetchSub (mirrors
    // gatewayWorkerMain). Counter returns to zero; no wrap.
    _ = q.popWait().?;
    _ = counter.fetchSub(1, .acq_rel);
    try std.testing.expectEqual(@as(usize, 1), counter.load(.acquire));
    _ = q.popWait().?;
    _ = counter.fetchSub(1, .acq_rel);
    try std.testing.expectEqual(@as(usize, 0), counter.load(.acquire));

    // An overflow-rejected push (queue full) must NOT bump the counter — the
    // add is coupled to a successful enqueue.
    var full = RequestQueue.init(std.testing.allocator, 1);
    full.depth_counter = &counter;
    defer full.deinit();
    try std.testing.expect(full.push(fakeConnForTest())); // fills capacity
    try std.testing.expectEqual(@as(usize, 1), counter.load(.acquire));
    try std.testing.expect(!full.push(fakeConnForTest())); // rejected, no bump
    try std.testing.expectEqual(@as(usize, 1), counter.load(.acquire));
    _ = full.popWait().?; // drain so deinit() closes nothing
    _ = counter.fetchSub(1, .acq_rel);
}

test "C3 RequestQueue add/sub ordering: concurrent push+pop never underflows the counter" {
    // Regression for Finding-C3-1: with the increment done in the acceptor
    // AFTER push() released the queue mutex, a worker could pop the connection
    // and fetchSub BEFORE the matching fetchAdd, transiently wrapping the
    // unsigned counter to ~1.8e19 and false-positiving the deadlock watchdog.
    // Now push() increments under the queue mutex (happens-before the pop), so
    // the decrement can never precede its increment. Stress it: a producer
    // pushes N items while a consumer pops+subs them concurrently; the counter
    // must always stay within [0, N] (never a huge wrapped value) and settle
    // back to the exact residual depth.
    var counter = std.atomic.Value(usize).init(0);
    var q = RequestQueue.init(std.testing.allocator, 4096);
    q.depth_counter = &counter;
    defer q.deinit();

    const N: usize = 2000;
    const Ctx = struct {
        q: *RequestQueue,
        counter: *std.atomic.Value(usize),
        n: usize,
        max_seen: std.atomic.Value(usize) = std.atomic.Value(usize).init(0),
        underflowed: std.atomic.Value(bool) = std.atomic.Value(bool).init(false),
        popped: std.atomic.Value(usize) = std.atomic.Value(usize).init(0),
    };
    var ctx = Ctx{ .q = &q, .counter = &counter, .n = N };

    const producer = struct {
        fn run(c: *Ctx) void {
            var i: usize = 0;
            while (i < c.n) : (i += 1) {
                while (!c.q.push(fakeConnForTest())) {
                    std.Thread.yield() catch {};
                }
                // Sample the counter from the producer side too; it must never
                // exceed N (a wrap would read as a near-usize-max value).
                const v = c.counter.load(.acquire);
                if (v > c.max_seen.load(.acquire)) c.max_seen.store(v, .release);
                if (v > c.n) c.underflowed.store(true, .release);
            }
        }
    };
    const consumer = struct {
        fn run(c: *Ctx) void {
            var got: usize = 0;
            while (got < c.n) {
                const conn = c.q.popWait() orelse break;
                _ = conn;
                // Mirror gatewayWorkerMain: decrement on pop. If a wrap ever
                // happened this would read as a huge value before sub.
                const before = c.counter.load(.acquire);
                if (before == 0 or before > c.n) c.underflowed.store(true, .release);
                _ = c.counter.fetchSub(1, .acq_rel);
                got += 1;
            }
            c.popped.store(got, .release);
        }
    };

    var t_prod = try std.Thread.spawn(.{}, producer.run, .{&ctx});
    var t_cons = try std.Thread.spawn(.{}, consumer.run, .{&ctx});
    t_prod.join();
    t_cons.join();

    try std.testing.expect(!ctx.underflowed.load(.acquire));
    try std.testing.expect(ctx.max_seen.load(.acquire) <= N);
    try std.testing.expectEqual(N, ctx.popped.load(.acquire));
    // All produced items consumed → counter settles back to zero, no wrap.
    try std.testing.expectEqual(@as(usize, 0), counter.load(.acquire));
}

test "C3 healthFastPathResponse: wedged pool fails liveness with 503 deadlocked" {
    // End-to-end at the response level (what the cheap /health fast-path
    // actually emits), exercising the same helper used by both the acceptor
    // inline path and the worker path.
    health.reset();
    health.markComponentOk("gateway"); // registry all-ok, so only the watchdog matters

    var state = GatewayState.init(std.testing.allocator);
    defer state.deinit();
    state.liveness_deadlock_threshold_ms = 180_000;

    // WEDGED: pending work + last completion far in the past relative to now.
    // (We can't inject `now` into the helper — it reads milliTimestamp — so we
    // place last progress well before "now" by parking it near epoch; the gap
    // is decades, comfortably past 180s, with pending work present.)
    state.queued_requests.store(3, .release);
    state.last_worker_progress_ms.store(0, .release);
    const wedged = healthFastPathResponse(&state);
    try std.testing.expectEqualStrings("503 Service Unavailable", wedged.status);
    try std.testing.expectEqualStrings("{\"status\":\"deadlocked\"}", wedged.body);

    // IDLE: no pending work → 200 ok even though progress is ancient.
    state.queued_requests.store(0, .release);
    const idle = healthFastPathResponse(&state);
    try std.testing.expectEqualStrings("200 OK", idle.status);
    try std.testing.expectEqualStrings("{\"status\":\"ok\"}", idle.body);

    // BUSY: pending work but a worker just completed (progress ~= now) → 200 ok.
    state.queued_requests.store(3, .release);
    state.last_worker_progress_ms.store(std.time.milliTimestamp(), .release);
    const busy = healthFastPathResponse(&state);
    try std.testing.expectEqualStrings("200 OK", busy.status);
    try std.testing.expectEqualStrings("{\"status\":\"ok\"}", busy.body);

    health.reset();
}

test "C3 healthFastPathResponse: degraded registry stays 200 (liveness unchanged)" {
    // A degraded component is a readiness/observability signal, not a liveness
    // kill — the watchdog must NOT promote it to 503. This pins that the only
    // 503 path through cheap /health is a genuine worker-pool deadlock.
    health.reset();
    health.markComponentError("database", "connection refused");

    var state = GatewayState.init(std.testing.allocator);
    defer state.deinit();
    state.liveness_deadlock_threshold_ms = 180_000;
    state.queued_requests.store(0, .release); // not wedged

    const resp = healthFastPathResponse(&state);
    try std.testing.expectEqualStrings("200 OK", resp.status);
    try std.testing.expectEqualStrings("{\"status\":\"degraded\"}", resp.body);

    health.reset();
}

