    cfg.gateway.allow_public_bind = true; // forces production-like

    const result = applyStartupSelfCheck(&gs, &cfg, error.ConnectionRefused, "0.0.0.0");
    try std.testing.expectError(error.ProductionPostgresRequired, result);
}

