    defer gs.deinit();
    const payload = try metricsPayload(allocator, &gs);
    defer allocator.free(payload);

    try std.testing.expect(std.mem.indexOf(u8, payload, "nullalis_trace_share_total{op=\"create\",result=\"ok\"} 1") != null);
}

